'use client';

import { useState } from 'react';

interface SignUpProps {
  onBack: () => void;
}

export default function SignUp({ onBack }: SignUpProps) {
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [school, setSchool] = useState('');
  const [major, setMajor] = useState('');

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();

    if (email && password && school && major) {
      // Store user data in localStorage (for demo purposes)
      const userData = { email, password, school, major };
      localStorage.setItem('userData', JSON.stringify(userData));
      localStorage.setItem('userId', email);
      console.log('Sign up successful:', userData);

      // Redirect to home page
      window.location.href = '/';
    } else {
      alert('Please fill in all fields');
    }
  };

  return (
    <div className="w-full max-w-md rounded-lg bg-white p-8 shadow-md">
      <h1 className="mb-6 text-center text-2xl font-bold">Sign Up</h1>
      <form onSubmit={handleSubmit} className="space-y-4">
        <div>
          <label htmlFor="email" className="mb-2 block text-sm font-medium">
            Email
          </label>
          <input
            type="email"
            id="email"
            value={email}
            onChange={(e) => setEmail(e.target.value)}
            className="w-full rounded-lg border border-gray-300 px-4 py-2 focus:ring-2 focus:ring-blue-800 focus:outline-none"
            required
          />
        </div>
        <div>
          <label htmlFor="password" className="mb-2 block text-sm font-medium">
            Password
          </label>
          <input
            type="password"
            id="password"
            value={password}
            onChange={(e) => setPassword(e.target.value)}
            className="w-full rounded-lg border border-gray-300 px-4 py-2 focus:ring-2 focus:ring-blue-800 focus:outline-none"
            required
          />
        </div>
        <div>
          <label htmlFor="school" className="mb-2 block text-sm font-medium">
            School
          </label>
          <select
            id="school"
            value={school}
            onChange={(e) => setSchool(e.target.value)}
            className="w-full rounded-lg border border-gray-300 px-4 py-2 focus:ring-2 focus:ring-blue-800 focus:outline-none"
            required
          >
            <option value="">Select a school</option>
            <option value="StonyBrook University">StonyBrook University</option>
            <option value="FIT">FIT</option>
            <option value="University of Utah">University of Utah</option>
          </select>
        </div>
        <div>
          <label htmlFor="major" className="mb-2 block text-sm font-medium">
            Major
          </label>
          <input
            type="text"
            id="major"
            value={major}
            onChange={(e) => setMajor(e.target.value)}
            className="w-full rounded-lg border border-gray-300 px-4 py-2 focus:ring-2 focus:ring-blue-800 focus:outline-none"
            required
          />
        </div>
        <button
          type="submit"
          className="w-full rounded-lg bg-blue-800 py-2 font-semibold text-white transition hover:bg-blue-700"
        >
          Sign Up
        </button>
        <button
          type="button"
          onClick={onBack}
          className="w-full rounded-lg bg-gray-400 py-2 font-semibold text-white transition hover:bg-gray-500"
        >
          Back to Login
        </button>
      </form>
    </div>
  );
}